openscad:
case_diameter = 40; // [20:1:60]
case_height = 9; // [5:0.5:15]
dial_diameter = 36; // [15:1:55]
dial_thickness = 1.5; // [0.5:0.5:4]
bezel_width = 2; // [0.5:0.5:5]
crown_diameter = 5; // [3:0.5:8]
crown_length = 6; // [3:0.5:12]
marker_width = 1.2; // [0.5:0.2:3]
marker_length = 3; // [1:0.5:6]
$fn = 60;

module watch() {
    // Black case
    color("black")
    difference() {
        cylinder(d=case_diameter, h=case_height, center=true);
        translate([0, 0, case_height/2 - 0.5])
            cylinder(d=case_diameter - bezel_width*2, h=2, center=true);
    }

    // White dial
    color("white")
    translate([0, 0, case_height/2 - 0.8])
        cylinder(d=dial_diameter, h=dial_thickness, center=true);

    // Hour markers
    color("black")
    for (i = [0:11]) {
        rotate([0, 0, i*30])
            translate([dial_diameter/2 - marker_length - 1.5, 0, case_height/2 - 0.3])
                cube([marker_length, marker_width, dial_thickness + 0.6], center=true);
    }

    // Crown
    color("black")
    translate([case_diameter/2 - 1, 0, 0])
        rotate([0, 90, 0])
            cylinder(d=crown_diameter, h=crown_length, center=true);
}

watch();
